215	void ftNcclStreamSynchronize(NcclParam tensor_para, NcclParam pipeline_para, cudaStream_t stream)
216	{
217	    FT_LOG_DEBUG("%s start", __PRETTY_FUNCTION__);
218	#ifdef BUILD_MULTI_GPU
219	    cudaError_t  cudaErr;
220	    ncclResult_t tensor_ncclErr = ncclSuccess, tensor_ncclAsyncErr = ncclSuccess, pipeline_ncclErr = ncclSuccess,
221	                 pipeline_ncclAsyncErr = ncclSuccess;
222	    ncclComm_t tensor_comm             = tensor_para.nccl_comm_;
223	    ncclComm_t pipeline_comm           = pipeline_para.nccl_comm_;
224	    if (tensor_para.world_size_ == 1 && pipeline_para.world_size_ == 1) {
225	        check_cuda_error(cudaStreamSynchronize(stream));
226	        return;
227	    }
228	    while (1) {
229	        cudaErr = cudaStreamQuery(stream);
230	        if (cudaErr == cudaSuccess) {
231	            FT_LOG_DEBUG("%s stop", __PRETTY_FUNCTION__);
232	            return;
233	        }
234	
235	        if (cudaErr != cudaErrorNotReady) {
236	            std::string error_msg = "CUDA Error : cudaStreamQuery returned " + std::to_string(cudaErr);
237	            throw std::runtime_error(error_msg);
238	        }
239	        if (tensor_para.world_size_ > 1) {
240	            tensor_ncclErr = ncclCommGetAsyncError(tensor_comm, &tensor_ncclAsyncErr);
241	        }
242	        if (pipeline_para.world_size_ > 1) {
243	            pipeline_ncclErr = ncclCommGetAsyncError(pipeline_comm, &pipeline_ncclAsyncErr);
244	        }
245	
246	        if (tensor_ncclErr != ncclSuccess || pipeline_ncclErr != ncclSuccess) {
247	            std::string error_msg = "NCCL Error : ncclCommGetAsyncError returned " + std::to_string(tensor_ncclErr)
248	                                    + " (tensor_para) " + std::to_string(pipeline_ncclErr) + " (pipeline_para)";
249	            throw std::runtime_error(error_msg);
250	        }
251	
252	        if (tensor_ncclAsyncErr != ncclSuccess) {
253	            // An asynchronous error happened. Stop the operation and destroy
254	            // the communicator
255	            tensor_ncclErr = ncclCommAbort(tensor_comm);
256	            if (tensor_ncclErr != ncclSuccess) {
257	                std::string error_msg = "NCCL Error : ncclCommDestroy returned " + std::to_string(tensor_ncclErr);
258	                throw std::runtime_error(error_msg);
259	            }
260	        }
261	
262	        if (pipeline_ncclAsyncErr != ncclSuccess) {
263	            // An asynchronous error happened. Stop the operation and destroy
264	            // the communicator
265	            pipeline_ncclErr = ncclCommAbort(pipeline_comm);
266	            if (pipeline_ncclErr != ncclSuccess) {
267	                std::string error_msg = "NCCL Error : ncclCommDestroy returned " + std::to_string(pipeline_ncclErr);
268	                throw std::runtime_error(error_msg);
269	            }
270	        }
271	    }
272	#endif
273	}
