308	void ftNcclInitialize(NcclParam& tensor_para,
309	                      NcclParam& pipeline_para,
310	                      const int  tensor_para_size,
311	                      const int  pipeline_para_size)
312	{
313	    FT_LOG_DEBUG("%s start", __PRETTY_FUNCTION__);
314	    // Initialize nccl communication grid of tensor and pipeline parallel groups.
315	#ifndef BUILD_MULTI_GPU
316	    FT_CHECK_WITH_INFO(tensor_para_size == 1,
317	                       fmtstr("tensor_para_size=%d although BUILD_MULTI_GPU is disabled. "
318	                              "Please use the cmake flag -DBUILD_MULTI_GPU=ON if you want "
319	                              "to use tensor/pipeline parallelism.",
320	                              tensor_para_size));
321	    FT_CHECK_WITH_INFO(pipeline_para_size == 1,
322	                       fmtstr("pipeline_para_size=%d although BUILD_MULTI_GPU is disabled. "
323	                              "Please use the cmake flag -DBUILD_MULTI_GPU=ON if you want "
324	                              "to use tensor/pipeline parallelism.",
325	                              pipeline_para_size));
326	    tensor_para.rank_         = 0;
327	    tensor_para.world_size_   = tensor_para_size;
328	    pipeline_para.rank_       = 0;
329	    pipeline_para.world_size_ = pipeline_para_size;
330	#else
331	    // Initialize a nccl communicator.
332	    if (tensor_para.nccl_comm_ != nullptr && pipeline_para.nccl_comm_ != nullptr) {
333	        FT_LOG_WARNING("NcclParam is already initialized. Skip NCCL initialization.");
334	        return;
335	    }
336	    FT_CHECK(tensor_para.nccl_comm_ == nullptr);
337	    FT_CHECK(pipeline_para.nccl_comm_ == nullptr);
338	    FT_CHECK(tensor_para_size > 0);
339	    FT_CHECK(pipeline_para_size > 0);
340	
341	    if (tensor_para_size == 1 && pipeline_para_size == 1) {
342	        FT_LOG_WARNING("Skip NCCL initialization since requested tensor/pipeline parallel sizes are equals to 1.");
343	        tensor_para.rank_         = 0;
344	        tensor_para.world_size_   = tensor_para_size;
345	        pipeline_para.rank_       = 0;
346	        pipeline_para.world_size_ = pipeline_para_size;
347	        return;
348	    }
349	
350	    int mpi_initialized;
351	    MPICHECK(MPI_Initialized(&mpi_initialized));
352	    FT_CHECK_WITH_INFO(mpi_initialized, "Fail to nccl initialization because MPI is not initialized.");
353	
354	    int rank, world_size;
355	    MPICHECK(MPI_Comm_rank(MPI_COMM_WORLD, &rank));
356	    MPICHECK(MPI_Comm_size(MPI_COMM_WORLD, &world_size));
357	
358	    FT_CHECK_WITH_INFO(tensor_para_size * pipeline_para_size <= world_size,
359	                       fmtstr("tensor_para_size (%d) * pipeline_para_size (%d) should equal to the world size (%d).",
360	                              tensor_para_size,
361	                              pipeline_para_size,
362	                              world_size));
363	
364	    // Convert WORLD communicator into 2D grid (k * n) communicator.
365	    //  row = a tensor parallel group, col = a pipeline parallel group.
366	    MPI_Comm grid_comm, tp_comm, pp_comm;
367	
368	    int dims[2]    = {pipeline_para_size, tensor_para_size};
369	    int periods[2] = {0, 0};
370	    MPI_Cart_create(MPI_COMM_WORLD, 2, dims, periods, 0, &grid_comm);
371	
372	    // Split 2D communicator into rows and cols.
373	    int tp_remain_dims[2] = {false, true};
374	    int pp_remain_dims[2] = {true, false};
375	    MPI_Cart_sub(grid_comm, tp_remain_dims, &tp_comm);
376	    MPI_Cart_sub(grid_comm, pp_remain_dims, &pp_comm);
377	
378	    int tp_rank, pp_rank;
379	    MPI_Comm_rank(tp_comm, &tp_rank);
380	    MPI_Comm_rank(pp_comm, &pp_rank);
381	
382	    ncclUniqueId tp_uid;
383	    ncclUniqueId pp_uid;
384	    // The root of each group creates a nccl uid.
385	    if (tp_rank == 0) {
386	        FT_LOG_DEBUG("rank %d pp rank %d creates nccl uid.", rank, tp_rank);
387	        NCCLCHECK(ncclGetUniqueId(&tp_uid));
388	    }
389	    if (pp_rank == 0) {
390	        FT_LOG_DEBUG("rank %d pp rank %d creates nccl uid.", rank, pp_rank);
391	        NCCLCHECK(ncclGetUniqueId(&pp_uid));
392	    }
393	    // Broadcast nccl uid to share the same nccl uid across gpus in the same group.
394	    FT_LOG_DEBUG("Broadcast nccl uid to the others in the same parallel groups.");
395	    MPI_Bcast(&tp_uid, sizeof(tp_uid), MPI_BYTE, 0, tp_comm);
396	    MPI_Bcast(&pp_uid, sizeof(pp_uid), MPI_BYTE, 0, pp_comm);
397	
398	    FT_LOG_DEBUG("Initialize NCCL communicators.");
399	    ncclComm_t tp_nccl_comm, pp_nccl_comm;
400	    NCCLCHECK(ncclCommInitRank(&tp_nccl_comm, tensor_para_size, tp_uid, tp_rank));
401	    NCCLCHECK(ncclCommInitRank(&pp_nccl_comm, pipeline_para_size, pp_uid, pp_rank));
402	
403	    tensor_para.world_size_   = tensor_para_size;
404	    tensor_para.rank_         = tp_rank;
405	    tensor_para.nccl_uid_     = tp_uid;
406	    tensor_para.nccl_comm_    = tp_nccl_comm;
407	    pipeline_para.world_size_ = pipeline_para_size;
408	    pipeline_para.rank_       = pp_rank;
409	    pipeline_para.nccl_uid_   = pp_uid;
410	    pipeline_para.nccl_comm_  = pp_nccl_comm;
411	    FT_LOG_INFO("NCCL initialized rank=%d world_size=%d tensor_para=%s pipeline_para=%s",
412	                rank,
413	                world_size,
414	                tensor_para.toString().c_str(),
415	                pipeline_para.toString().c_str());
416	#endif
417	    FT_LOG_DEBUG("%s stop", __PRETTY_FUNCTION__);
418	}
419	
420	size_t getLocalBatchSize(const size_t batch_size, const size_t seq_len, const size_t pipeline_para_size)
421	{
422	    size_t local_batch_size = batch_size;
423	    if (pipeline_para_size == 1) {
424	        return local_batch_size;
425	    }
426	    if (local_batch_size % pipeline_para_size == 0) {
427	        local_batch_size /= pipeline_para_size;
428	    }
429	    while (local_batch_size * seq_len > 1024 && local_batch_size % 2 == 0) {
430	        local_batch_size /= 2;
431	    }
432	    return local_batch_size;
433	}
